 2→
 3→import android.webkit.WebResourceRequest
 4→import android.webkit.WebResourceResponse
 5→import android.webkit.WebView
 6→import android.webkit.WebViewClient
 7→
 8→class CourtWebViewClient(
 9→    private val onPdfDetected: (url: String) -> Unit,
10→    private val onPageLoaded: () -> Unit
11→) : WebViewClient() {
12→
13→    override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
14→        val url = request?.url?.toString() ?: return false
15→        if (isPdfUrl(url)) {
16→            onPdfDetected(url)
17→            return true
18→        }
19→        return false
20→    }
21→
22→    override fun shouldInterceptRequest(view: WebView?, request: WebResourceRequest?): WebResourceResponse? {
23→        val url = request?.url?.toString() ?: return null
24→        // 拦截通过 XHR/fetch 等方式请求的 PDF URL
25→        if (isPdfUrl(url) && request.method.equals("GET", ignoreCase = true)) {
26→            view?.post { onPdfDetected(url) }
27→            return null
28→        }
29→        return null
30→    }
31→
32→    override fun onPageFinished(view: WebView?, url: String?) {
33→        super.onPageFinished(view, url)
34→        onPageLoaded()
35→        // 注入JS：拦截通过 window.open 或 JS 触发的 PDF 链接
36→        view?.evaluateJavascript("""
37→            (function() {
38→                if (window._courtPdfHooked) return;
39→                window._courtPdfHooked = true;
40→                document.addEventListener('click', function(e) {
41→                    var el = e.target;
42→                    while (el && el.tagName !== 'A') el = el.parentElement;
43→                    if (el && el.href) {
44→                        var href = el.href.toLowerCase();
45→                        if (href.endsWith('.pdf') || href.indexOf('.pdf?') !== -1
46→                            || href.indexOf('getpdf') !== -1 || href.indexOf('download') !== -1
47→                            || href.indexOf('文书') !== -1) {
48→                            window.location.href = el.href;
49→                        }
50→                    }
51→                }, true);
52→                var origOpen = window.open;
53→                window.open = function(url) {
54→                    if (url) window.location.href = url;
55→                    return null;
56→                };
57→            })();
58→        """.trimIndent(), null)
59→    }
60→
61→    private fun isPdfUrl(url: String): Boolean {
62→        val lower = url.lowercase()
63→        return lower.endsWith(".pdf") || lower.contains(".pdf?")
64→            || lower.contains("getpdf") || lower.contains("download") && lower.contains("pdf")
65→    }
66→}
