 3→import java.io.File
 4→import java.security.MessageDigest
 5→
 6→object Md5Util {
 7→    /**
 8→     * 计算文件的MD5哈希值
 9→     */
10→    fun calculateMd5(file: File): String {
11→        val md = MessageDigest.getInstance("MD5")
12→        file.inputStream().use { fis ->
13→            val buffer = ByteArray(8192)
14→            var bytesRead: Int
15→            while (fis.read(buffer).also { bytesRead = it } != -1) {
16→                md.update(buffer, 0, bytesRead)
17→            }
18→        }
19→        return md.digest().joinToString("") { "%02x".format(it) }
20→    }
21→
22→    /**
23→     * 计算字节数组的MD5哈希值
24→     */
25→    fun calculateMd5(bytes: ByteArray): String {
26→        val md = MessageDigest.getInstance("MD5")
27→        md.update(bytes)
28→        return md.digest().joinToString("") { "%02x".format(it) }
29→    }
30→}
